CustomField.formula:
IF( ISBLANK(Phone_Number__c), "",
/* +1 — USA / Canada (11 digits, e.g. 12025551234 → (+1) 202-555-1234) */ IF( AND(LEN(Phone_Number__c) = 11, LEFT(Phone_Number__c, 1) = "1"), "(+1) " & MID(Phone_Number__c, 2, 3) & "-" & MID(Phone_Number__c, 5, 3) & "-" & MID(Phone_Number__c, 8, 4),
/* +91 — India (12 digits) */ IF( AND(LEN(Phone_Number__c) = 12, LEFT(Phone_Number__c, 2) = "91"), "(+91) " & MID(Phone_Number__c, 3, 10),
/* +44 — UK (12 digits) */ IF( AND(LEN(Phone_Number__c) = 12, LEFT(Phone_Number__c, 2) = "44"), "(+44) " & MID(Phone_Number__c, 3, 10),
/* +61 — Australia (11 digits) */ IF( AND(LEN(Phone_Number__c) = 11, LEFT(Phone_Number__c, 2) = "61"), "(+61) " & MID(Phone_Number__c, 3, 9),
/* +49 — Germany (12 digits, can vary 11-13) */ IF( AND(LEN(Phone_Number__c) >= 11, LEN(Phone_Number__c) <= 13, LEFT(Phone_Number__c, 2) = "49"), "(+49) " & MID(Phone_Number__c, 3, LEN(Phone_Number__c) - 2),
/* +33 — France (11 digits) */ IF( AND(LEN(Phone_Number__c) = 11, LEFT(Phone_Number__c, 2) = "33"), "(+33) " & MID(Phone_Number__c, 3, 9),
/* +81 — Japan (11-12 digits) */ IF( AND(LEN(Phone_Number__c) >= 11, LEN(Phone_Number__c) <= 12, LEFT(Phone_Number__c, 2) = "81"), "(+81) " & MID(Phone_Number__c, 3, LEN(Phone_Number__c) - 2),
/* +86 — China (13 digits) */ IF( AND(LEN(Phone_Number__c) = 13, LEFT(Phone_Number__c, 2) = "86"), "(+86) " & MID(Phone_Number__c, 3, 11),
/* +65 — Singapore (10 digits) */ IF( AND(LEN(Phone_Number__c) = 10, LEFT(Phone_Number__c, 2) = "65"), "(+65) " & MID(Phone_Number__c, 3, 8),
/* +971 — UAE (12 digits) */ IF( AND(LEN(Phone_Number__c) = 12, LEFT(Phone_Number__c, 3) = "971"), "(+971) " & MID(Phone_Number__c, 4, 9),
/* +966 — Saudi Arabia (12 digits) */ IF( AND(LEN(Phone_Number__c) = 12, LEFT(Phone_Number__c, 3) = "966"), "(+966) " & MID(Phone_Number__c, 4, 9),
/* +880 — Bangladesh (13 digits) */ IF( AND(LEN(Phone_Number__c) = 13, LEFT(Phone_Number__c, 3) = "880"), "(+880) " & MID(Phone_Number__c, 4, 10),
/* +92 — Pakistan (12 digits) */ IF( AND(LEN(Phone_Number__c) = 12, LEFT(Phone_Number__c, 2) = "92"), "(+92) " & MID(Phone_Number__c, 3, 10),
/* +94 — Sri Lanka (11 digits) */ IF( AND(LEN(Phone_Number__c) = 11, LEFT(Phone_Number__c, 2) = "94"), "(+94) " & MID(Phone_Number__c, 3, 9),
/* +977 — Nepal (13 digits) */ IF( AND(LEN(Phone_Number__c) = 13, LEFT(Phone_Number__c, 3) = "977"), "(+977) " & MID(Phone_Number__c, 4, 10),
/* Fallback — unknown country, prepend + */ "+" & Phone_Number__c
))))))))))))))))
